mapper.update:
UPDATE bids
SET status = 'REJECTED',
    updated_at = NOW()
WHERE request_id = #{requestId}
  AND bid_id != #{selectedBidId}
  AND status = 'ACTIVE'

mapper.select:
SELECT COUNT(*)
FROM bids
WHERE request_id = #{requestId}
  AND business_id = #{businessId}
  AND status != 'HIDDEN'

SELECT request_id, hope_price, status
FROM request
WHERE request_id = #{requestId}
